/**
 * Circle of fifths — a data-first key model (no UI).
 *
 * The circle is generated by stepping fifths from C in both directions, so the
 * structure itself (not a hardcoded note table) produces every key, its
 * relative minor, and its accidental count. Key signatures are derived from a
 * key's position on the circle: N sharps = the first N of F C G D A E B; N flats
 * = the first N of B E A D G C F.
 */

import {
  parseNote, formatNote, pitchClass, LETTER_FIFTHS, stepLetter, accidentalFor
} from "./notes.js";

const SHARP_ORDER = ["F", "C", "G", "D", "A", "E", "B"];
const FLAT_ORDER = ["B", "E", "A", "D", "G", "C", "F"];

/** Signed circle-of-fifths position: C=0, G=+1, F=-1, F#=+6, Db=-5. */
export function fifthsOf(note) {
  const n = parseNote(note);
  return LETTER_FIFTHS[n.letter] + 7 * n.accidental;
}

/** Relative minor of a major key: down a minor third (the 6th degree). */
export function relativeMinor(majorRoot) {
  const r = parseNote(majorRoot);
  const { letter } = stepLetter(r.letter, 5); // +5 letters == -2 (a third down)
  const targetPc = (pitchClass(r) + 9) % 12;  // major 6th up == relative minor
  return formatNote({ letter, accidental: accidentalFor(letter, targetPc), octave: null });
}

/** Relative major of a minor key: up a minor third (the bIII). */
export function relativeMajor(minorRoot) {
  const r = parseNote(minorRoot);
  const { letter } = stepLetter(r.letter, 2);
  const targetPc = (pitchClass(r) + 3) % 12;
  return formatNote({ letter, accidental: accidentalFor(letter, targetPc), octave: null });
}

/**
 * Key signature for a key.
 * @returns {{ count, type: "sharp"|"flat"|"none", notes: string[] }}
 */
export function getKeySignature(root, quality = "major") {
  const majorTonic = quality === "minor" ? relativeMajor(root) : root;
  const fifths = fifthsOf(majorTonic);
  if (fifths === 0) return { count: 0, type: "none", notes: [] };
  if (fifths > 0) {
    return { count: fifths, type: "sharp", notes: SHARP_ORDER.slice(0, fifths).map((l) => `${l}#`) };
  }
  const count = -fifths;
  return { count, type: "flat", notes: FLAT_ORDER.slice(0, count).map((l) => `${l}b`) };
}

/** Build the full 12-position circle starting at C, going clockwise (fifths up). */
export function buildCircle() {
  const entries = [];
  let letter = "C";
  let accidental = 0;
  for (let i = 0; i < 12; i += 1) {
    const major = formatNote({ letter, accidental, octave: null });
    entries.push({
      position: i,
      major,
      minor: `${relativeMinor(major)}m`,
      fifths: fifthsOf(major),
      keySignature: getKeySignature(major, "major")
    });
    // Step up a perfect fifth: +4 letters, +7 semitones.
    const next = stepLetter(letter, 4);
    const targetPc = (pitchClass({ letter, accidental, octave: null }) + 7) % 12;
    letter = next.letter;
    accidental = accidentalFor(letter, targetPc);
  }
  return entries;
}

export const CIRCLE = buildCircle();

/** Neighboring keys: subdominant (−fifth), dominant (+fifth), and relatives. */
export function neighbors(root, quality = "major") {
  const r = parseNote(root);
  const up = stepLetter(r.letter, 4);
  const upPc = (pitchClass(r) + 7) % 12;
  const dominant = formatNote({ letter: up.letter, accidental: accidentalFor(up.letter, upPc), octave: null });

  const down = stepLetter(r.letter, 3); // -4 letters mod 7
  const downPc = (pitchClass(r) + 5) % 12;
  const subdominant = formatNote({ letter: down.letter, accidental: accidentalFor(down.letter, downPc), octave: null });

  return {
    dominant,
    subdominant,
    relative: quality === "major" ? `${relativeMinor(root)}m` : relativeMajor(root),
    parallel: quality === "major" ? `${formatNote({ ...r, octave: null })}m` : formatNote({ ...r, octave: null })
  };
}
